var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"……확실히 강력하군요.","JPN":"……確かに手強い相手ですね。","ENG":"…He sure is strong, just as I expected.","TWN":"……確實滿強的！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"지금도 저 정도의 힘을 뿜어내는 걸 보면 완성된 후에는 훨씬 더 귀찮아질 겁니다.","JPN":"今でもあれほどの力を出せる以上、完成した後はもっと厄介になるでしょう。","ENG":"If he's that strong already, he'll be a real pain in the neck once he's completed.","TWN":"半成品就已經可以發揮如此強的力量，完成後會更難對付！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그럴 바에는 차라리 여기서 처치하는 게 좋지 않을까요?","JPN":"それならいっそここで退治した方がいいんじゃないですか？","ENG":"Why don't we just take it out now?","TWN":"與其這樣，倒不如現在就將他斬草除根吧？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"나유빈! 너 무슨 소릴 하는 거야?","JPN":"イチノセ！　あなた、何を言っているの？","ENG":"Yubin! What are you talking about?","TWN":"羅瑜斌！你在說什麼！"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 녀석은 내 사원이라고! 함부로 손대는 건 용납 못해!","JPN":"あの子はうちの社員よ！　勝手に手を出すのは許さないわ！","ENG":"He's my employee! I won't let you hurt him!","TWN":"他可是我的員工！你如果敢對他出手我絕不饒你！"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 수연아, 너도 알고 있잖아.","JPN":"でもキズナ、君も知ってるだろ？","ENG":"But you get it too, don't you?","TWN":"秀妍你應該聽過這句話吧？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"계획을 세우는 입장에서 변수는 그리 환영할 만한 존재가 아니라는 걸.","JPN":"計画を立てる立場として、不確定要素はあまり歓迎すべき存在ではないということを。","ENG":"When it comes to planning, nobody likes a variable.","TWN":"所謂計畫趕不上變化。"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그건 스승님도 마찬가지일 테고요.","JPN":"それは師匠も同じでしょう。","ENG":"I'm sure you feel the same way, Master.","TWN":"師父應該也認同吧？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……말했을 텐데.","JPN":"……言ったはずだ。","ENG":"…Have I not made it clear?","TWN":"……我說過了，"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"우린 여기에 주시윤을 구출하기 위해 온 거다.","JPN":"私たちはアキヤマを救出するためにここに来た。","ENG":"We are here to save Joo Shiyoon.","TWN":"我們來這裡是要救周時雲。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"나와 함께 행동할 생각이라면 내 지휘를 따라라, 나유빈.","JPN":"私と一緒に行動するつもりなら私の指揮に従え、イチノセ。","ENG":"If you wish to stay with me, you will submit to my command, Na Yubin.","TWN":"你想和我一起行動的話就乖乖聽我的指揮，羅瑜斌！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"너, 루크레시아라고 했던가?","JPN":"お前、ルクレシアと言ったか？","ENG":"You. Lucrecia, was it?","TWN":"你叫露可蕾西亞？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……그렇습니다만.","JPN":"……そうですが。","ENG":"…Aye.","TWN":"……是沒錯。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"이쯤에서 끝내고 돌아가라.","JPN":"この辺にして帰れ。","ENG":"Just call it day and go.","TWN":"到此為止，你們回去吧！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"최초의 용혈로 제련한 용인이라고 해도, 지금 우리 둘을 상대로는 승산이 없어.","JPN":"原初の龍血で製錬した龍人でも、今の私たち2人を相手に勝算はない。","ENG":"You stand no chance against the two of us, even if you've forged that Dragonoid from the first Dragon Blood.","TWN":"就算他是用原始的龍血煉製而成的龍人，以他目前的能力是打不贏我們的。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"이대로 계속 싸워 봤자 그 미완성의 용인만 잃을 뿐이다.","JPN":"このまま戦い続けたところで、その未完成の龍人を失うだけだ。","ENG":"If you keep fighting, you'll only lose your unfinished Dragonoid.","TWN":"再打下去，結果就是你會失去那個半成品的龍人。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"결국……. 당신도 제자의 목숨은 아깝다는 거군요.","JPN":"結局……あなたも弟子の命は手放せないのですね。","ENG":"So… You value your apprentice's life in the end.","TWN":"說到底……你也是會擔心徒弟的性命的。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};